}

#include <iostream>
#include <cmath>
using namespace std;
class Point {
    double x, y;
public:
    Point(double x = 0, double y = 0) : x(x), y(y) {}
    Point(const Point& p) : x(p.x), y(p.y) {}
    double getX() const { return x; }
    double getY() const { return y; }
};
class Rectangle {
    Point leftBottom, rightTop;
public:
    Rectangle(Point lb, Point rt) : leftBottom(lb), rightTop(rt) {}
    Rectangle(const Rectangle& r)
        : leftBottom(r.leftBottom), rightTop(r.rightTop) {}
    double area() const {
        return fabs((rightTop.getX() - leftBottom.getX()) *
                    (rightTop.getY() - leftBottom.getY()));
    }
};
int main() {
    Rectangle r(Point(0, 0), Point(3, 4));
    cout << r.area() << endl;
    return 0;
}

