#include <iostream>
#include <fstream>
using namespace std;
class Dog {
private:
    double weight;
    int age;
public:
    Dog(double w = 0, int a = 0) : weight(w), age(a) {}
    void show() const {
        cout << "weight=" << weight << ", age=" << age << endl;
    }
    void save(ofstream& out) const {
        out << weight << " " << age << endl;
    }
    void load(ifstream& in) {
        in >> weight >> age;
    }
};
int main() {
    Dog dog1(5, 10);
    ofstream fout("dog.txt");
    dog1.save(fout);
    fout.close();
    Dog dog2;
    ifstream fin("dog.txt");
    dog2.load(fin);
    fin.close();
    dog2.show();
    return 0;
}

