#include <iostream>
using namespace std;
class Point {
    double x, y;
public:
    Point(double x=0, double y=0) : x(x), y(y) {}
    Point(const Point& p) : x(p.x), y(p.y) {}
    void move(double dx, double dy) { x += dx; y += dy; }
    void show() const { cout << "(" << x << "," << y << ")"; }
};
class AdvCircle {
    Point center;
    double radius;
public:
    AdvCircle(Point c = Point(), double r = 0) : center(c), radius(r) {}
    AdvCircle(const AdvCircle& other)
        : center(other.center), radius(other.radius) {}
    double area() const { return 3.14159 * radius * radius; }
    void move(double dx, double dy) { center.move(dx, dy); }
    void show() const {
        cout << "center=";
        center.show();
        cout << ", radius=" << radius << ", area=" << area() << endl;
    }
};
int main() {
    AdvCircle c1(Point(1, 2), 3);
    AdvCircle c2(c1);
    c2.move(5, 6);
    c1.show();
    c2.show();
    return 0;
}
